window.PACTO.acts["dec_framw-2002-584"]={"label": "DECISIONE QUADRO DEL CONSIGLIO", "short": "Dec. quadro 584/2002", "file": "ext-dec_framw-2002-584.html", "external": true, "version": "consolidato 2009-03-28", "eurlex": "https://eur-lex.europa.eu/eli/dec_framw/2002/584/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Definizione del mandato d'arresto europeo ed obbligo di darne esecuzione", "anchor": "art_1", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il mandato d'arresto europeo è una decisione giudiziaria emessa da uno Stato membro in vista dell'arresto e della consegna da parte di un altro Stato membro di una persona ricercata ai fini dell'esercizio di un'azione penale o dell'esecuzione di una pena o una misura di sicurezza privative della libertà.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri danno esecuzione ad ogni mandato d'arresto europeo in base al principio del riconoscimento reciproco e conformemente alle disposizioni della presente decisione quadro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L'obbligo di rispettare i diritti fondamentali e i fondamentali principi giuridici sanciti dall'articolo 6 del trattato sull'Unione europea non può essere modificata per effetto della presente decisione quadro.</div>\n</div>"]]}, "2": {"label": "Articolo 2", "heading": "Campo d'applicazione del mandato d'arresto europeo", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il mandato d'arresto europeo può essere emesso per dei fatti puniti dalle leggi dello Stato membro emittente con una pena privativa della libertà o con una misura di sicurezza privative della libertà della durata massima non inferiore a dodici mesi oppure, se è stata disposta la condanna a una pena o è stata inflitta una misura di sicurezza, per condanne pronunciate di durata non inferiore a quattro mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Danno luogo a consegna in base al mandato d'arresto europeo, alle condizioni stabilite dalla presente decisione quadro e indipendentemente dalla doppia incriminazione per il reato, i reati seguenti, quali definiti dalla legge dello Stato membro emittente, se in detto Stato membro il massimo della pena o della misura di sicurezza privative della libertà per tali reati è pari o superiore a tre anni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">partecipazione a un'organizzazione criminale,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">terrorismo,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">tratta di esseri umani,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sfruttamento sessuale dei bambini e pornografia infantile,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di stupefacenti e sostanze psicotrope,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di armi, munizioni ed esplosivi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">corruzione,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">frode, compresa la frode che lede gli interessi finanziari delle Comunità europee ai sensi della convenzione del 26 luglio 1995 relativa alla tutela degli interessi finanziari delle Comunità europee,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">riciclaggio di proventi di reato,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">falsificazione di monete, compresa la contraffazione dell'euro,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">criminalità informatica,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">criminalità ambientale, compreso il traffico illecito di specie animali protette e il traffico illecito di specie e di essenze vegetali protette,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">favoreggiamento dell'ingresso e del soggiorno illegali,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">omicidio volontario, lesioni personali gravi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di organi e tessuti umani,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">rapimento, sequestro e presa di ostaggi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">razzismo e xenofobia,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">furti organizzati o con l'uso di armi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di beni culturali, compresi gli oggetti d'antiquariato e le opere d'arte,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">truffa,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">racket e estorsioni,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">contraffazione e pirateria in materia di prodotti,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">falsificazione di atti amministrativi e traffico di documenti falsi,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">falsificazione di mezzi di pagamento,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di sostanze ormonali ed altri fattori di crescita,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico illecito di materie nucleari e radioattive,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">traffico di veicoli rubati,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">stupro,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">incendio volontario,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">reati che rientrano nella competenza giurisdizionale della Corte penale internazionale,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">dirottamento di aereo/nave,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sabotaggio.</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Consiglio può decidere in qualsiasi momento, deliberando all'unanimità e previa consultazione del Parlamento europeo alle condizioni di cui all'articolo 39, paragrafo 1, del trattato sull'Unione europea (TUE), di inserire altre categorie di reati nell'elenco di cui al paragrafo 2 del presente articolo. Il Consiglio esamina, alla luce della relazione sottopostagli dalla Commissione ai sensi dell'articolo 34, paragrafo 3, se sia opportuno estendere o modificare tale elenco.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda i reati non contemplati dal paragrafo 2, la consegna può essere subordinata alla condizione che i fatti per i quali è stato emesso il mandato d'arresto europeo costituiscano un reato ai sensi della legge dello Stato membro di esecuzione indipendentemente dagli elementi costitutivi o dalla qualifica dello stesso.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Motivi di non esecuzione obbligatoria del mandato di arresto europeo", "anchor": "art_3", "frags": [[null, "<p class=\"norm\">L'autorità giudiziaria dello Stato membro di esecuzione (in prosieguo: «autorità giudiziaria dell'esecuzione») rifiuta di eseguire il mandato d'arresto europeo nei casi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il reato alla base del mandato d'arresto è coperto da amnistia nello Stato membro di esecuzione, se quest'ultimo era competente a perseguire il reato secondo la propria legge penale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se in base ad informazioni in possesso dell'autorità giudiziaria dell'esecuzione risulta che la persona ricercata è stata giudicata con sentenza definitiva per gli stessi fatti da uno Stato membro a condizione che, in caso di condanna, la sanzione sia stata applicata o sia in fase di esecuzione o non possa più essere eseguita in forza delle leggi dello Stato membro della condanna;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la persona oggetto del mandato d'arresto europeo non può ancora essere considerata, a causa dell'età, penalmente responsabile dei fatti all'origine del mandato d'arresto europeo in base alla legge dello Stato membro di esecuzione.</p>\n</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Motivi di non esecuzione facoltativa del mandato di arresto europeo", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">L'autorità giudiziaria dell'esecuzione può rifiutare di eseguire il mandato d'arresto europeo:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se, in uno dei casi di cui all'articolo 2, paragrafo 4, il fatto che è alla base del mandato d'arresto europeo non costituisce reato ai sensi della legge dello Stato membro di esecuzione; tuttavia in materia di tasse e di imposte, di dogana e di cambio, l'esecuzione del mandato di arresto europeo non può essere rifiutata in base al fatto che la legislazione dello Stato membro di esecuzione non impone lo stesso tipo di tasse o di imposte o non contiene lo stesso tipo di normativa in materia di tasse, di imposte, di dogana e di cambio della legislazione dello Stato membro emittente;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se contro la persona oggetto del mandato d'arresto europeo è in corso un'azione nello Stato membro di esecuzione per il medesimo fatto che è alla base del mandato d'arresto europeo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se le autorità giudiziarie dello Stato membro dell'esecuzione hanno deciso di non esercitare l'azione penale per il reato oggetto del mandato d'arresto europeo oppure di porvi fine, o se la persona ricercata ha formato oggetto in uno Stato membro di una sentenza definitiva per gli stessi fatti che osta all'esercizio di ulteriori azioni;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l'azione penale o la pena è caduta in prescrizione secondo la legislazione dello Stato membro di esecuzione e i fatti rientrano nella competenza di tale Stato membro in virtù del proprio diritto penale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se in base ad informazioni in possesso dell'autorità giudiziaria dell'esecuzione risulta che la persona ricercata è stata giudicata con sentenza definitiva per gli stessi fatti da un paese terzo a condizione che, in caso di condanna, la sanzione sia stata applicata o sia in fase di esecuzione o non possa più essere eseguita in forza delle leggi del paese della condanna;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il mandato d'arresto europeo è stato rilasciato ai fini dell'esecuzione di una pena o di una misura di sicurezza privative della libertà, qualora la persona ricercata dimori nello Stato membro di esecuzione, ne sia cittadino o vi risieda, se tale Stato si impegni a eseguire esso stesso tale pena o misura di sicurezza conformemente al suo diritto interno;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Se il mandato d'arresto europeo riguarda reati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che dalla legge dello Stato membro di esecuzione sono considerati commessi in tutto o in parte nel suo territorio, o in un luogo assimilato al suo territorio; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che sono stati commessi al di fuori del territorio dello Stato membro emittente, se la legge dello Stato membro di esecuzione non consente l'azione penale per gli stessi reati commessi al di fuori del suo territorio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "4a": {"label": "Articolo 4 bis", "heading": "Decisioni pronunciate al termine di un processo a cui l’interessato non è comparso personalmente", "anchor": "art_4a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità giudiziaria dell’esecuzione può altresì rifiutare di eseguire il mandato d’arresto europeo emesso ai fini dell’esecuzione di una pena o di una misura di sicurezza privative della libertà se l’interessato non è comparso personalmente al processo terminato con la decisione, salvo che il mandato d’arresto europeo indichi che l’interessato, conformemente agli ulteriori requisiti processuali definiti nel diritto interno dello Stato membro emittente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a tempo debito:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato citato personalmente ed è quindi stato informato della data e del luogo fissati per il processo terminato con la decisione o è stato di fatto informato ufficialmente con altri mezzi della data e del luogo fissati per il processo, in modo tale che si è stabilito inequivocabilmente che era al corrente del processo fissato;</p>\n<p class=\"list\">e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato informato del fatto che una decisione poteva essere emessa in caso di mancata comparizione in giudizio;</p>\n</div>\n</div>\n<p class=\"list\">o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">essendo al corrente della data fissata, aveva conferito un mandato ad un difensore, nominato dall’interessato o dallo Stato, per patrocinarlo in giudizio, ed è stato in effetti patrocinato in giudizio da tale difensore;</p>\n<p class=\"list\">o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dopo aver ricevuto la notifica della decisione ed essere stato espressamente informato del diritto a un nuovo processo o ad un ricorso in appello cui l’interessato ha il diritto di partecipare e che consente di riesaminare il merito della causa, comprese le nuove prove, e può condurre alla riforma della decisione originaria:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ha dichiarato espressamente di non opporsi alla decisione;</p>\n<p class=\"list\">o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non ha richiesto un nuovo processo o presentato ricorso in appello entro il termine stabilito;</p>\n</div>\n</div>\n<p class=\"list\">o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non ha ricevuto personalmente la notifica della decisione, ma:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riceverà personalmente e senza indugio la notifica dopo la consegna e sarà espressamente informato del diritto a un nuovo processo o ad un ricorso in appello cui l’interessato ha il diritto di partecipare e che consente di riesaminare il merito della causa, comprese le nuove prove, e può condurre alla riforma della decisione originaria;</p>\n<p class=\"list\">e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sarà informato del termine entro cui deve richiedere un nuovo processo o presentare ricorso in appello, come stabilito nel mandato d’arresto europeo pertinente.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora il mandato d’arresto europeo sia emesso ai fini dell’esecuzione di una pena o di una misura di sicurezza privative della libertà alle condizioni di cui al paragrafo 1, lettera d), e l’interessato non sia stato precedentemente informato ufficialmente dell’esistenza di un procedimento penale a suo carico, questi può, una volta informato del contenuto del mandato d’arresto europeo, chiedere che gli sia trasmessa copia della sentenza prima della consegna. Non appena ricevuta informazione della richiesta, l’autorità emittente fornisce all’interessato copia della sentenza per il tramite dell’autorità di esecuzione. La richiesta dell’interessato non ritarda la procedura di consegna né la decisione di eseguire il mandato d’arresto europeo. La sentenza è trasmessa all’interessato a soli fini informativi; la trasmissione non costituisce notificazione ufficiale della sentenza né fa decorrere i termini applicabili per la richiesta di un nuovo processo o per la presentazione di un ricorso in appello.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora la persona sia consegnata alle condizioni di cui al paragrafo 1, lettera d), e abbia chiesto un nuovo processo o presentato ricorso in appello, la detenzione della persona in attesa di tale processo o appello è riesaminata, fino alla conclusione del procedimento, conformemente al diritto dello Stato membro di emissione, a intervalli regolari o su richiesta dell’interessato. Il riesame verte in particolare sulla possibilità di sospensione o interruzione della detenzione. Il nuovo processo o l’appello hanno inizio in tempo utile dalla consegna.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "5": {"label": "Articolo 5", "heading": "Garanzie che lo Stato emittente deve fornire in casi particolari", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">L'esecuzione del mandato d'arresto europeo da parte dell'autorità giudiziaria dell'esecuzione può essere subordinata dalla legge dello Stato membro di esecuzione ad una delle seguenti condizioni:</p>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Se il reato in base al quale il mandato d'arresto europeo è stato emesso è punibile con una pena o una misura di sicurezza privative della libertà a vita, l'esecuzione di tale mandato può essere subordinata alla condizione che lo Stato membro emittente preveda nel suo ordinamento giuridico una revisione della pena comminata — su richiesta o al più tardi dopo 20 anni — oppure l'applicazione di misure di clemenza alle quali la persona ha diritto in virtù della legge o della prassi dello Stato membro di emissione, affinché la pena o la misura in questione non siano eseguite.</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Se la persona oggetto del mandato d'arresto europeo ai fini di un'azione penale è cittadino o residente dello Stato membro di esecuzione, la consegna può essere subordinata alla condizione che la persona, dopo essere stata ascoltata, sia rinviata nello Stato membro di esecuzione per scontarvi la pena o la misura di sicurezza privative della libertà eventualmente pronunciate nei suoi confronti nello Stato membro emittente.</p>\n</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Determinazione delle autorità giudiziarie competenti", "anchor": "art_6", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per autorità giudiziaria emittente si intende l'autorità giudiziaria dello Stato membro emittente che, in base alla legge di detto Stato, è competente a emettere un mandato d'arresto europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per autorità giudiziaria dell'esecuzione si intende l'autorità giudiziaria dello Stato membro di esecuzione che, in base alla legge di detto Stato, è competente dell'esecuzione del mandato di arresto europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro comunica al Segretariato generale del Consiglio qual è l'autorità competente in base al proprio diritto interno.</div>\n</div>"]]}, "7": {"label": "Articolo 7", "heading": "Ricorso all'autorità centrale", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro può designare un'autorità centrale o, quando il suo ordinamento giuridico lo prevede, delle autorità centrali per assistere le autorità giudiziarie competenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Uno Stato membro può, se l'organizzazione del proprio sistema giudiziario interno lo rende necessario, affidare alla (alle) propria (proprie) autorità centrale (centrali) la trasmissione e la ricezione amministrativa dei mandati d'arresto europei e della corrispondenza ufficiale ad essi relativa.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro che voglia avvalersi delle facoltà descritte nel presente articolo comunica al Segretariato generale del Consiglio le informazioni relative all'autorità centrale (alle autorità centrali) designata(e). Dette indicazioni sono vincolanti per tutte le autorità dello Stato membro emittente.</p>"]]}, "8": {"label": "Articolo 8", "heading": "Contenuto e forma del mandato d'arresto europeo", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il mandato d'arresto europeo contiene le informazioni seguenti, nella presentazione stabilita dal modello allegato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">identità e cittadinanza del ricercato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il nome, l'indirizzo, il numero di telefono e di fax, l'indirizzo di posta elettronica dell'autorità giudiziaria emittente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indicazione dell'esistenza di una sentenza esecutiva, di un mandato d'arresto o di qualsiasi altra decisione giudiziaria esecutiva che abbia la stessa forza e che rientri nel campo d'applicazione degli articoli 1 e 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">natura e qualificazione giuridica del reato, in particolare tenendo conto dell'articolo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">descrizione delle circostanze della commissione del reato, compreso il momento, il luogo e il grado di partecipazione del ricercato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pena inflitta, se vi è una sentenza definitiva, ovvero, negli altri casi, pena minima e massima stabilita dalla legge dello Stato di emissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto possibile, le altre conseguenze del reato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il mandato di arresto europeo è tradotto nella lingua ufficiale o in una delle lingue ufficiali dello Stato membro di esecuzione. Ciascuno Stato membro può al momento dell'adozione della presente decisione quadro, o successivamente, attestare in una dichiarazione depositata presso il Segretariato generale del Consiglio che accetterà una traduzione in una o più lingue ufficiali delle istituzioni delle Comunità europee.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Trasmissione di un mandato d'arresto europeo", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando il luogo in cui si trova il ricercato è conosciuto, l'autorità giudiziaria emittente può comunicare il mandato d'arresto europeo direttamente all'autorità giudiziaria dell'esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria emittente può, in ogni caso, decidere di segnalare la persona ricercata nel Sistema di Informazione Schengen (SIS).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Siffatta segnalazione è effettuata conformemente alle disposizioni dell'articolo 95 della convenzione del 19 giugno 1990, di applicazione dell'accordo di Schengen del 14 giugno 1985 relativo all'eliminazione graduale dei controlli alle frontiere comuni. Una segnalazione nel Sistema di Informazione Schengen equivale a un mandato d'arresto europeo corredato delle informazioni di cui all'articolo 8, paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">Per un periodo transitorio, fintanto che il SIS non sarà in grado di trasmettere tutte le informazioni di cui all'articolo 8, la segnalazione equivarrà ad un mandato d'arresto europeo in attesa del ricevimento in debita forma dell'originale da parte dell'autorità giudiziaria dell'esecuzione.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Modalità di trasmissione di un mandato d'arresto europeo", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se l'autorità giudiziaria emittente ignora quale sia l'autorità giudiziaria dell'esecuzione competente, effettua le ricerche necessarie, specie attraverso i punti di contatto della Rete giudiziaria europea (\n<span class=\"superscript\">1</span>\n), per ottenere tale informazione dallo Stato di esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se l'autorità giudiziaria emittente lo desidera, la trasmissione può essere effettuata mediante il sistema di telecomunicazione protetto della Rete giudiziaria europea.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se non è possibile ricorrere al Sistema di Informazione Schengen, l'autorità giudiziaria emittente può fare ricorso ai servizi dell'Interpol per comunicare il mandato d'arresto europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria emittente può trasmettere il mandato d'arresto europeo con qualsiasi mezzo sicuro in grado di produrre una registrazione scritta a condizioni che consentano allo Stato membro dell'esecuzione di verificarne l'autenticità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualsiasi difficoltà relativa alla trasmissione o all'autenticità di un documento necessario per l'esecuzione del mandato d'arresto europeo è risolta attraverso contatti diretti tra le autorità giudiziarie interessate o, se del caso, con l'intervento delle autorità centrali degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se l'autorità che riceve un mandato d'arresto europeo non ha la competenza per dargli seguito, lo trasmette d'ufficio alla sua autorità nazionale competente e ne informa l'autorità giudiziaria emittente.</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Diritti del ricercato", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando il ricercato è arrestato l'autorità giudiziaria dell'esecuzione competente lo informa, in conformità con il proprio diritto interno, del mandato d'arresto europeo e del suo contenuto, nonché della possibilità di acconsentire alla propria consegna all'autorità giudiziaria emittente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il ricercato arrestato in esecuzione di un mandato d'arresto europeo ha il diritto di essere assistito da un consulente legale e da un interprete, conformemente al diritto interno dello Stato membro di esecuzione.</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Mantenimento in custodia", "anchor": "art_12", "frags": [[null, "<p class=\"norm\">Quando una persona viene arrestata sulla base di un mandato d'arresto europeo, l'autorità giudiziaria dell'esecuzione decide se la persona debba o meno rimanere in stato di custodia conformemente al diritto interno dello Stato membro dell'esecuzione. In qualsiasi momento è possibile la rimessa in libertà provvisoria, conformemente al diritto interno dello Stato membro di esecuzione, a condizione che l'autorità competente di tale Stato membro adotti le misure ritenute necessarie ad evitare che il ricercato si dia alla fuga.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Consenso alla consegna", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se l'arrestato indica di acconsentire alla propria consegna, il consenso ed eventualmente la rinuncia espressa al beneficio della regola della specialità, definita all'articolo 27, paragrafo 2, sono raccolti dall'autorità giudiziaria dell'esecuzione in conformità con il diritto interno dello Stato membro di esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro adotta le misure necessarie affinché il consenso ed eventualmente la rinuncia di cui al paragrafo 1 siano raccolti in condizioni dalle quali risulti che l'interessato li ha espressi volontariamente e con piena consapevolezza delle conseguenze. A tal fine il ricercato ha diritto all'assistenza di un consulente legale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il consenso ed eventualmente la rinuncia di cui al paragrafo 1 sono verbalizzati secondo la procedura prevista dal diritto interno dello Stato membro di esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il consenso è in linea di massima irrevocabile. Ciascuno Stato membro può prevedere la revocabilità del consenso ed eventualmente della rinuncia in conformità con le norme applicabili di diritto interno. In tal caso per fissare i termini di cui all'articolo 17 non si tiene conto del periodo che intercorre tra la data del consenso e quella della revoca. Lo Stato membro che desidera sfruttare detta possibilità ne informa il Segretariato generale del Consiglio dell'Unione europea all'atto dell'adozione della presente decisione quadro e indica le modalità in base alle quali è possibile la revoca del consenso nonché qualsiasi modifica.</div>\n</div>"]]}, "14": {"label": "Articolo 14", "heading": "Audizione del ricercato", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Se non dà il consenso alla propria consegna secondo le modalità di cui all'articolo 13 l'arrestato ha diritto all'audizione a cura dell'autorità giudiziaria dell'esecuzione in conformità con il diritto interno di tale Stato membro dell'esecuzione.</p>"]]}, "15": {"label": "Articolo 15", "heading": "Decisione sulla consegna", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione decide la consegna della persona nei termini e alle condizioni stabilite dalla presente decisione quadro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione che non ritiene le informazioni comunicatele dallo Stato membro emittente sufficienti per permetterle di prendere una decisione sulla consegna, richiede urgentemente le informazioni complementari necessarie segnatamente in relazione agli articoli 3, 4, 5 e 8 e può stabilire un termine per la ricezione delle stesse, tenendo conto dell'esigenza di rispettare i termini fissati all'articolo 17.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria emittente può, in qualsiasi momento, trasmettere tutte le informazioni supplementari utili all'autorità giudiziaria dell'esecuzione.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Decisione in caso di concorso di richieste", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se due o più Stati membri hanno emesso un mandato di arresto europeo nei confronti della stessa persona, l'autorità giudiziaria dell'esecuzione decide quale dei mandati di arresto deve essere eseguito, tenuto debito conto di tutte le circostanze e soprattutto della gravità relativa e del luogo in cui è avvenuto il reato, delle date rispettive di emissione dei mandati di arresto europei nonché del fatto che i mandati sono stati emessi ai fini dell'azione penale o per l'esecuzione di una pena o misura privative della libertà.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione può richiedere una consulenza all'Eurojust (\n<span class=\"superscript\">2</span>\n) per prendere la decisione di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di conflitto tra un mandato di arresto europeo ed una richiesta di estradizione presentata da un paese terzo, la competente autorità dell'esecuzione decide se dare la precedenza al mandato di arresto europeo o alla richiesta di estradizione, tenuto debito conto di tutte le circostanze, in particolare di quelle di cui al paragrafo 1 e di quelle indicate nella convenzione o nell'accordo applicabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il presente articolo lascia impregiudicati gli obblighi degli Stati membri che derivano dallo Statuto istitutivo della Corte penale internazionale.</div>\n</div>"]]}, "17": {"label": "Articolo 17", "heading": "Termini e modalità della decisione di esecuzione del mandato di arresto europeo", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un mandato d'arresto europeo deve essere trattato ed eseguito con la massima urgenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui il ricercato acconsente alla propria consegna, la decisione definitiva sull'esecuzione del mandato d'arresto europeo dovrebbe essere presa entro 10 giorni dalla comunicazione del consenso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Negli altri casi, la decisione definitiva sull'esecuzione del mandato d'arresto europeo dovrebbe essere presa entro 60 giorni dall'arresto del ricercato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In casi particolari, se il mandato d'arresto europeo non può essere eseguito entro i termini di cui ai paragrafi 2 o 3, l'autorità giudiziaria dell'esecuzione ne informa immediatamente l'autorità giudiziaria emittente e ne indica i motivi. In questi casi i termini possono essere prorogati di 30 giorni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fintanto che l'autorità giudiziaria dell'esecuzione non prende una decisione definitiva sull'esecuzione del mandato d'arresto europeo, essa si accerterà che siano soddisfatte le condizioni materiali necessarie per la consegna effettiva.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualsiasi rifiuto di eseguire un mandato d'arresto europeo deve essere motivato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se, in circostanze eccezionali, uno Stato membro non è in grado di rispettare i termini stabiliti dal presente articolo, esso ne informa l'Eurojust, indicando i motivi del ritardo. Inoltre, uno Stato membro che ha subito ritardi ripetuti nell'esecuzione dei mandati d'arresto da parte di un altro Stato membro ne informa il Consiglio affinché sia valutata l'attuazione della presente decisione quadro a livello degli Stati membri.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Situazione in attesa della decisione", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il mandato d'arresto europeo è stato emesso per esercitare un'azione penale l'autorità giudiziaria dell'esecuzione deve:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">o accettare che si proceda all'audizione del ricercato, ai sensi dell'articolo 19 o;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accettare il trasferimento temporaneo del ricercato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le condizioni e la durata del trasferimento temporaneo sono definite di comune accordo tra l'autorità giudiziaria emittente e l'autorità giudiziaria dell'esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di trasferimento temporaneo la persona deve poter tornare nello Stato membro di esecuzione per assistere alle udienze che la riguardano nel quadro della procedura di consegna.</div>\n</div>"]]}, "19": {"label": "Articolo 19", "heading": "Audizione della persona in attesa della decisione", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'audizione della persona ricercata è effettuata da un'autorità giudiziaria, assistita da un'altra persona designata conformemente alla legislazione dello Stato membro dell'autorità giudiziaria richiedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L'audizione del ricercato è effettuata conformemente alla legislazione dello Stato membro di esecuzione e le condizioni determinate di comune accordo dall'autorità giudiziaria emittente e l'autorità giudiziaria dell'esecuzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La competente autorità giudiziaria dell'esecuzione può incaricare un'altra autorità giudiziaria del proprio Stato membro di partecipare all'audizione del ricercato al fine di garantire una corretta applicazione del presente articolo e delle condizioni precedentemente stabilite.</div>\n</div>"]]}, "20": {"label": "Articolo 20", "heading": "Privilegi e immunità", "anchor": "art_20", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se il ricercato beneficia di un privilegio o di un'immunità di giurisdizione o di esecuzione nello Stato membro di esecuzione, il termine di cui all'articolo 17 comincia a decorrere solo se e a partire dal giorno in cui l'autorità giudiziaria dell'esecuzione è stata informata del fatto che tale privilegio o immunità è revocato.</div>\n</div>"], [null, "<p class=\"norm\">Lo Stato membro di esecuzione assicura che saranno soddisfatte le condizioni materiali necessarie per la consegna effettiva, nel momento in cui la persona non beneficerà più di tale privilegio o immunità.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se la revoca del privilegio o dell'immunità compete ad un'autorità dello Stato membro di esecuzione, l'autorità giudiziaria dell'esecuzione le inoltra prontamente la richiesta. Se è invece competente un'autorità di un altro Stato o organizzazione internazionale, spetta all'autorità giudiziaria emittente farne richiesta.</div>\n</div>"]]}, "21": {"label": "Articolo 21", "heading": "Conflitto di obblighi internazionali", "anchor": "art_21", "frags": [[null, "<p class=\"norm\">La presente decisione quadro non pregiudica gli obblighi dello Stato membro di esecuzione qualora il ricercato vi sia stato estradato da uno Stato terzo e sia tutelato dalle norme in materia di specialità contenute nell'accordo in virtù del quale ha avuto luogo l'estradizione. Lo Stato membro di esecuzione prende tutte le misure necessarie per chiedere immediatamente l'assenso dello Stato dal quale il ricercato è stato estradato in modo che questi possa essere consegnato allo Stato membro emittente. I termini di cui all'articolo 17 cominciano a decorrere solo dal giorno in cui dette norme in materia di specialità cessano di essere applicate. In attesa della decisione dello Stato da cui il ricercato è stato estradato, lo Stato membro di esecuzione si accerterà che siano soddisfatte le condizioni materiali necessarie per la consegna effettiva.</p>"]]}, "22": {"label": "Articolo 22", "heading": "Notifica della decisione", "anchor": "art_22", "frags": [[null, "<p class=\"norm\">L'autorità giudiziaria dell'esecuzione notifica immediatamente all'autorità giudiziaria emittente la decisione riguardante il seguito dato al mandato d'arresto europeo.</p>"]]}, "23": {"label": "Articolo 23", "heading": "Termine per la consegna", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il ricercato è consegnato al più presto, a una data concordata tra le autorità interessate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Egli è consegnato al più tardi entro dieci giorni a partire dalla decisione definitiva di eseguire il mandato d'arresto europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nel caso in cui la consegna del ricercato entro il termine di cui al paragrafo 2 sia impedita da cause di forza maggiore per uno degli Stati membri, l'autorità giudiziaria dell'esecuzione e l'autorità giudiziaria emittente si contattano immediatamente e concordano una nuova data per la consegna. In tal caso, la consegna avviene entro i dieci giorni successivi alla nuova data concordata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La consegna può, a titolo eccezionale, essere temporaneamente differita per gravi motivi umanitari, ad esempio se vi sono valide ragioni di ritenere che essa metterebbe manifestamente in pericolo la vita o la salute del ricercato. Il mandato d'arresto europeo viene eseguito non appena tali motivi cessano di sussistere. L'autorità giudiziaria dell'esecuzione ne informa immediatamente l'autorità giudiziaria emittente e concorda una nuova data per la consegna. In tal caso, la consegna avviene entro i dieci giorni successivi alla nuova data concordata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Allo scadere dei termini previsti ai paragrafi da 2 a 4, se la persona continua a trovarsi in stato di custodia, essa è rilasciata.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Consegna rinviata o condizionale", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione può, dopo aver deciso l'esecuzione del mandato d'arresto europeo, rinviare la consegna del ricercato affinché questi possa essere sottoposto a procedimento penale nello Stato membro di esecuzione o, se è già stato condannato, affinché possa scontare nel suo territorio una pena prevista per un reato diverso da quello oggetto del mandato d'arresto europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Invece di rinviare la consegna, l'autorità giudiziaria dell'esecuzione può, a titolo temporaneo, consegnare allo Stato membro emittente il ricercato, secondo condizioni da determinare di comune accordo tra l'autorità giudiziaria dell'esecuzione e l'autorità giudiziaria emittente. Tale intesa avviene per iscritto e le condizioni sono vincolanti per tutte le autorità dello Stato membro emittente.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Transito", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuno Stato membro consente, salvo che si avvalga della possibilità di rifiutare qualora il transito di un suo cittadino o residente sia richiesto ai fini dell'esecuzione di una pena o di una misura di sicurezza privative della libertà, il transito attraverso il suo territorio di un ricercato che deve essere consegnato, purché abbia ricevuto informazioni circa:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'identità e la cittadinanza della persona oggetto del mandato d'arresto europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'esistenza di un mandato d'arresto europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la natura e la qualificazione giuridica del reato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione delle circostanze del reato, compresi la data ed il luogo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se la persona oggetto del mandato d'arresto europeo ai fini di un'azione penale è cittadino o residente dello Stato membro di transito, il transito può essere subordinato alla condizione che la persona, dopo essere stata ascoltata, sia rinviata nello Stato membro di transito per scontarvi la pena o la misura di sicurezza pronunciata nello Stato membro emittente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuno Stato membro designa un'autorità competente per la ricezione delle richieste di transito, dei documenti necessari e di qualsiasi altra corrispondenza ufficiale ad esse relativa. Gli Stati membri comunicano tale designazione al Segretariato generale del Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La richiesta di transito e le informazioni di cui al paragrafo 1 possono essere trasmesse all'autorità designata ai sensi del paragrafo 2 con qualsiasi mezzo che consenta di conservarne una traccia scritta. Lo Stato membro di transito rende nota la sua decisione con la medesima procedura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La presente decisione quadro non si applica, se sono utilizzate le vie aeree senza previsione di scalo. Tuttavia, in caso di atterraggio non programmato, lo Stato membro emittente fornisce all'autorità designata ai sensi del paragrafo 2 le informazioni di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se un transito riguarda una persona che deve essere estradata da un paese terzo verso uno Stato membro il presente articolo è applicabile mutatis mutandis. In particolare, l'espressione «mandato d'arresto europeo» sarà sostituita dai termini «richiesta di estradizione».</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "26": {"label": "Articolo 26", "heading": "Deduzione del periodo di custodia scontato nello Stato di esecuzione", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro emittente deduce il periodo complessivo di custodia che risulta dall'esecuzione di un mandato d'arresto europeo dalla durata totale della detenzione che dovrà essere scontata nello Stato emittente in seguito alla condanna a una pena o a una misura di sicurezza privative della libertà.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">A tal fine l'autorità giudiziaria dell'esecuzione o l'autorità centrale designata ai sensi dell'articolo 7 trasmette all'autorità giudiziaria emittente, all'atto della consegna, tutte le informazioni relative alla durata del periodo di custodia del ricercato in base al mandato d'arresto europeo.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Eventuali azioni penali per altri reati", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro può notificare al Segretariato generale del Consiglio dell'Unione europea che nei suoi rapporti con altri Stati membri che hanno effettuato la stessa notifica si presume che sia stato accordato l'assenso all'azione penale, alla condanna o alla detenzione ai fini dell'esecuzione di una pena o di una misura di sicurezza privative della libertà per eventuali reati anteriori alla consegna diversi da quello per cui è stato consegnato salvo che in un caso specifico l'autorità giudiziaria dell'esecuzione faccia una diversa dichiarazione nella sua decisione relativa alla consegna.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Salvi i casi previsti ai paragrafi 1 e 3, la persona non è sottoposta a un procedimento penale, condannata o altrimenti privata della libertà per eventuali reati anteriori alla consegna diversi da quello per cui è stata consegnata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il paragrafo 2 non si applica nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando, pur avendo avuto l'opportunità di farlo, la persona non ha lasciato il territorio dello Stato membro al quale è stato consegnato nei 45 giorni successivi alla scarcerazione definitiva oppure vi ha fatto ritorno dopo averlo lasciato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il reato non è punibile con una pena o una misura privative della libertà;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il procedimento penale non dà luogo all'applicazione di una misura restrittiva della libertà personale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora la persona sia soggetta ad una pena o misura che non implichi la privazione della libertà, ivi inclusa una misura pecuniaria, anche se può restringere la sua libertà personale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora la persona abbia acconsentito alla propria consegna, oltre a rinunciare, se del caso, alla regola della specialità, in conformità dell'articolo 13;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora, dopo essere stato consegnato, la persona abbia espressamente rinunciato a beneficiare della regola della specialità rispetto a particolari reati anteriori alla sua consegna. Tale rinuncia è raccolta dalle competenti autorità giudiziarie dello Stato membro emittente e verbalizzata in conformità con il diritto interno di quest'ultimo. Essa è redatta in modo che risulti che l'interessato l'ha espressa volontariamente e con piena consapevolezza delle conseguenze. A tal fine la persona ha diritto ad essere assistita da un consulente legale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora l'autorità giudiziaria dell'esecuzione che ha consegnato la persona dia il suo assenso in conformità del paragrafo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p>\n<span>\n<span class=\"boldface\">►C1</span>\n</span>\n</p>"], [null, "<p class=\"normal\"> </p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La richiesta di assenso è presentata all'autorità giudiziaria dell'esecuzione<span class=\"boldface\"> ◄ </span>, corredata delle informazioni di cui all'articolo 8, paragrafo 1, nonché di una traduzione, come previsto all'articolo 8, paragrafo 2. L'assenso è accordato qualora il reato per cui è richiesto dia esso stesso luogo a consegna conformemente al disposto della presente decisione quadro. L'assenso è rifiutato per i motivi di cui all'articolo 3 e, altrimenti, può essere rifiutato soltanto per i motivi di cui all'articolo 4. La decisione interviene entro i trenta giorni dal ricevimento della richiesta.</div>\n</div>"], [null, "<p class=\"norm\">Per le situazioni di cui all'articolo 5 lo Stato emittente deve fornire le garanzie ivi previste.</p>"]]}, "28": {"label": "Articolo 28", "heading": "Consegna o estradizione successiva", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni Stato membro può notificare al Segretariato generale del Consiglio che, nei suoi rapporti con altri Stati membri che hanno effettuato la stessa notifica, si presume che sia stato accordato l'assenso per la consegna della persona ad uno Stato membro, diverso dallo Stato membro di esecuzione, a seguito di un mandato d'arresto europeo emesso per un reato anteriore alla sua consegna, salvo che in un caso specifico l'autorità giudiziaria dell'esecuzione faccia una diversa dichiarazione nella sua decisione relativa alla consegna.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Una persona consegnata allo Stato membro emittente a seguito di un mandato d'arresto europeo può comunque essere consegnata senza l'assenso dello Stato membro di esecuzione ad uno Stato membro diverso dallo Stato membro di esecuzione a seguito di un mandato d'arresto europeo emesso per un reato anteriore alla sua consegna nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando, pur avendo avuto l'opportunità di farlo, il ricercato non ha lasciato il territorio dello Stato membro al quale è stato consegnato nei 45 giorni successivi alla sua scarcerazione definitiva oppure vi ha fatto ritorno dopo averlo lasciato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora il ricercato consenta ad essere consegnato ad uno Stato membro diverso dallo Stato membro di esecuzione a seguito di un mandato d'arresto europeo. Il consenso è raccolto dalle autorità giudiziarie competenti dello Stato membro emittente e verbalizzato in conformità con il diritto interno di quest'ultimo. Esso è redatto in modo che risulti che l'interessato l'ha espresso volontariamente e con piena consapevolezza delle conseguenze. A tal fine la persona ha diritto ad essere assistita da un consulente legale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">allorché il ricercato non beneficia della regola della specialità, in conformità dell'articolo 27, paragrafo 3, lettere a), e), f) e g).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione dà il suo assenso alla consegna ad un altro Stato membro secondo le seguenti regole:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la richiesta di assenso è presentata in conformità dell'articolo 9, corredata delle informazioni di cui all'articolo 8, paragrafo 1, nonché di una traduzione, come previsto all'articolo 8, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'assenso è accordato qualora il reato per cui è richiesto dia esso stesso luogo a consegna conformemente al disposto della presente decisione quadro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la decisione interviene entro trenta giorni dal ricevimento della richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l'assenso è rifiutato per i motivi di cui all'articolo 3 e può essere altrimenti rifiutato soltanto per i motivi di cui all'articolo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per le situazioni di cui all'articolo 5 lo Stato membro emittente deve fornire le garanzie ivi previste.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, la persona che è stata consegnata a seguito di un mandato d'arresto europeo non è estradata verso uno Stato terzo senza l'assenso delle autorità competenti dello Stato membro che ha provveduto alla consegna. L'assenso è accordato in conformità delle convenzioni che vincolano lo Stato membro che ha provveduto alla consegna del ricercato, nonché della legislazione nazionale del medesimo.</div>\n</div>"]]}, "29": {"label": "Articolo 29", "heading": "Consegna di beni", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L'autorità giudiziaria dell'esecuzione, in conformità della legislazione nazionale e a richiesta dell'autorità giudiziaria emittente o di sua iniziativa, confisca e consegna beni che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possono essere necessari come prova, ovvero</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono stati acquisiti dal ricercato a seguito del reato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I beni di cui al paragrafo 1 sono consegnati anche se il mandato d'arresto europeo non può essere eseguito a motivo del decesso o della fuga del ricercato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se i beni di cui al paragrafo 1 sono passibili di sequestro o confisca nel territorio dello Stato membro di esecuzione, quest'ultimo può, qualora i beni siano necessari in relazione ad un procedimento penale in corso, disporre che siano temporaneamente bloccati o consegnarli allo Stato membro emittente a condizione che siano successivamente restituiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Sono fatti salvi gli eventuali diritti sui beni di cui al paragrafo 1 acquisiti dallo Stato membro di esecuzione o da terzi. Ove tali diritti sussistano, lo Stato membro emittente restituisce i beni in questione, senza alcun onere, allo Stato membro di esecuzione quanto prima possibile dopo la fine del procedimento penale.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Spese", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le spese sostenute sul territorio dello Stato membro di esecuzione per l'esecuzione del mandato d'arresto europeo sono a carico di detto Stato membro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tutte le altre spese sono a carico dello Stato membro emittente.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "31": {"label": "Articolo 31", "heading": "Relazioni con gli altri strumenti giuridici", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatta salva la loro applicazione nelle relazioni tra Stati membri e paesi terzi, le disposizioni contenute nella presente decisione quadro sostituiscono, a partire dal 1<span class=\"superscript\">o</span> gennaio 2004, le corrispondenti disposizioni delle convenzioni seguenti applicabili in materia di estradizione nelle relazioni tra gli Stati membri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">convenzione europea di estradizione del 13 dicembre 1957, il relativo protocollo addizionale del 15 ottobre 1975, il relativo secondo protocollo aggiuntivo del 17 marzo 1978 e la convenzione europea per la repressione del terrorismo del 27 gennaio 1977 per la parte concernente l'estradizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accordo tra gli Stati membri delle Comunità europee sulla semplificazione e la modernizzazione delle modalità di trasmissione delle domande di estradizione del 26 maggio 1989;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">convenzione relativa alla procedura semplificata di estradizione tra gli Stati membri dell'Unione europea del 10 marzo 1995; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">convenzione relativa all'estradizione tra gli Stati membri dell'Unione europea del 27 settembre 1996;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">titolo III, capitolo 4, della convenzione del 19 giugno 1990 di applicazione dell'accordo di Schengen del 14 giugno 1985 relativo all'eliminazione graduale dei controlli alle frontiere comuni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono continuare ad applicare gli accordi o intese bilaterali o multilaterali vigenti al momento dell'adozione della presente decisione quadro nella misura in cui questi consentono di approfondire o di andare oltre gli obiettivi di quest'ultima e contribuiscono a semplificare o agevolare ulteriormente la consegna del ricercato.</div>\n</div>"], [null, "<p class=\"norm\">Gli Stati membri possono concludere accordi o intese bilaterali o multilaterali dopo l'entrata in vigore della presente decisione quadro nella misura in cui questi consentono di approfondire o di andare oltre il contenuto di quest'ultima e contribuiscono a semplificare o agevolare ulteriormente la consegna del ricercato, segnatamente fissando termini più brevi di quelli dell'articolo 17, estendendo l'elenco dei reati di cui all'articolo 2, paragrafo 2, riducendo ulteriormente i motivi di rifiuto di cui agli articoli 3 e 4 o abbassando la soglia di cui all'articolo 2, paragrafo 1 o 2.</p>"], [null, "<p class=\"norm\">Gli accordi e le convenzioni di cui al secondo comma non possono in alcun caso pregiudicare le relazioni con gli Stati membri che non sono parti degli stessi.</p>"], [null, "<p class=\"norm\">Gli Stati membri notificano al Consiglio e alla Commissione entro tre mesi dall'entrata in vigore della presente decisione quadro gli accordi e le intese esistenti di cui al primo comma che vogliono continuare ad applicare.</p>"], [null, "<p class=\"norm\">Gli Stati membri notificano inoltre al Consiglio e alla Commissione, entro tre mesi dalla firma, i nuovi accordi o le nuove intese come previsto al secondo comma.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Laddove gli accordi e le convenzioni di cui al paragrafo 1 si applichino a territori degli Stati membri ovvero a territori per i quali uno Stato membro si assume la competenza per le relazioni esterne, ai quali non si applica la presente decisione quadro, tali strumenti continuano a disciplinare le relazioni esistenti tra tali territori e gli altri Stati membri.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Disposizione transitoria", "anchor": "art_32", "frags": [[null, "<p class=\"norm\">Le richieste di estradizione ricevute anteriormente al 1<span class=\"superscript\">o</span> gennaio 2004 continueranno ad essere disciplinate dagli strumenti esistenti in materia di estradizione. Le richieste ricevute a partire dal 1<span class=\"superscript\">o</span> gennaio 2004 saranno soggette alle norme adottate dagli Stati membri conformemente alla presente decisione quadro. Tuttavia ogni Stato membro può, al momento dell'adozione della presente decisione quadro da parte del Consiglio, fare una dichiarazione secondo cui in qualità di Stato dell'esecuzione esso continuerà a trattare le richieste relative a reati commessi prima di una data da esso precisata conformemente al sistema di estradizione applicabile anteriormente al 1<span class=\"superscript\">o</span> gennaio 2004. La data in questione non può essere posteriore al 7 agosto 2002. Tale dichiarazione sarà pubblicata nella Gazzetta ufficiale e può essere ritirata in qualsiasi momento.</p>"]]}, "33": {"label": "Articolo 33", "heading": "Disposizioni relative all'Austria e a Gibilterra", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fintanto che non avrà modificato l'articolo 12, paragrafo 1 della «Auslieferungs- und Rechtshilfegesetz» e, al più tardi, sino al 31 dicembre 2008, l'Austria può autorizzare le proprie autorità giudiziarie dell'esecuzione a rifiutarsi di eseguire un mandato d'arresto europeo se il ricercato è un cittadino austriaco e se il reato per cui il mandato d'arresto europeo è stato emesso non è punibile a norma della legislazione austriaca.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La presente decisione si applica a Gibilterra.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Attuazione", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie per conformarsi alle disposizioni della presente decisione quadro il 31 dicembre 2003.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri trasmettono al Segretariato generale del Consiglio e alla Commissione il testo delle disposizioni inerenti al recepimento nella legislazione nazionale degli obblighi imposti dalla presente decisione quadro. Nel procedere in tal senso ciascuno Stato membro può indicare che applicherà immediatamente la presente decisione quadro nelle relazioni con gli Stati membri che hanno effettuato la stessa comunicazione.</div>\n</div>"], [null, "<p class=\"norm\">Il Segretariato generale del Consiglio comunica agli Stati membri e alla Commissione le informazioni ricevute a norma dell'articolo 7, paragrafo 2, dell'articolo 8, paragrafo 2, dell'articolo 13, paragrafo 4 e dell'articolo 25, paragrafo 2. Provvederà inoltre alla pubblicazione di tali informazioni nella Gazzetta ufficiale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Sulla base delle informazioni trasmesse dal Segretariato generale del Consiglio, la Commissione presenta al Parlamento europeo e al Consiglio, entro il 31 dicembre 2004, una relazione sull'applicazione della presente decisione quadro accompagnata, se opportuno, da proposte legislative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel secondo semestre del 2003 il Consiglio valuta in particolare l'applicazione pratica delle disposizioni della presente decisione quadro da parte degli Stati membri nonché il funzionamento del sistema di informazione Schengen.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Entrata in vigore", "anchor": "art_35", "frags": [[null, "<p class=\"norm\">La presente decisione quadro entra in vigore il ventesimo giorno successivo alla pubblicazione nella Gazzetta ufficiale.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};